import{_ as a,o,c as t,ag as r}from"./chunks/framework.CAXxHpAX.js";const f=JSON.parse('{"title":"Glossary","description":"Terms used across the Prova docs and codebase.","frontmatter":{"description":"Terms used across the Prova docs and codebase."},"headers":[],"relativePath":"reference/glossary.md","filePath":"reference/glossary.md","lastUpdated":1777130260000}'),i={name:"reference/glossary.md"};function s(n,e,c,d,l,h){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="glossary" tabindex="-1">Glossary <a class="header-anchor" href="#glossary" aria-label="Permalink to &quot;Glossary&quot;">​</a></h1><h2 id="active" tabindex="-1">Active <a class="header-anchor" href="#active" aria-label="Permalink to &quot;Active&quot;">​</a></h2><p>A deal is <code>Active</code> once the prover has fetched the bytes, verified the cid, and posted the first successful proof. Active deals receive payment per successful proof.</p><h2 id="cid-content-identifier" tabindex="-1">CID (Content Identifier) <a class="header-anchor" href="#cid-content-identifier" aria-label="Permalink to &quot;CID (Content Identifier)&quot;">​</a></h2><p>A self-describing, content-addressed identifier. Prova&#39;s <code>piece-cid</code> is a CIDv1 with multicodec <code>piece-commitment</code> and multihash <code>sha2-256-trunc254-padded</code>. See <a href="./../concepts/piece-cids">Piece-CIDs</a>.</p><h2 id="commp" tabindex="-1">CommP <a class="header-anchor" href="#commp" aria-label="Permalink to &quot;CommP&quot;">​</a></h2><p>The piece-commitment hash. A binary Merkle root over the file&#39;s bytes (with Fr32 padding). The on-chain <code>bytes32</code> representation of the cid. Used to verify proofs.</p><h2 id="deal" tabindex="-1">Deal <a class="header-anchor" href="#deal" aria-label="Permalink to &quot;Deal&quot;">​</a></h2><p>A contract between a client and a prover for storing one piece for one term. Deals are created, settled, and slashed by <code>StorageMarketplace.sol</code> on Base.</p><h2 id="escrow" tabindex="-1">Escrow <a class="header-anchor" href="#escrow" aria-label="Permalink to &quot;Escrow&quot;">​</a></h2><p>USDC the client locked into the marketplace contract when proposing the deal. Released to the prover proportionally as proofs land. Refunded to the client if the deal is cancelled or the prover is slashed.</p><h2 id="jti" tabindex="-1">JTI <a class="header-anchor" href="#jti" aria-label="Permalink to &quot;JTI&quot;">​</a></h2><p>The <code>jti</code> claim on a JWT — a unique identifier for one issued token. Used by Prova to revoke individual tokens without rotating the global signing key.</p><h2 id="pdp-proof-of-data-possession" tabindex="-1">PDP (Proof of Data Possession) <a class="header-anchor" href="#pdp-proof-of-data-possession" aria-label="Permalink to &quot;PDP (Proof of Data Possession)&quot;">​</a></h2><p>The cryptographic protocol Prova uses to verify a prover still has the bytes. Lighter than PoRep, no sealing, no SNARKs. See <a href="./../concepts/continuous-proof">Continuous proof of storage</a>.</p><h2 id="piece" tabindex="-1">Piece <a class="header-anchor" href="#piece" aria-label="Permalink to &quot;Piece&quot;">​</a></h2><p>A blob of bytes addressed by a piece-cid. Files larger than the per-piece limit are split client-side into multiple pieces.</p><h2 id="piece-cid" tabindex="-1">piece-cid <a class="header-anchor" href="#piece-cid" aria-label="Permalink to &quot;piece-cid&quot;">​</a></h2><p>The content-addressed id of a piece. See <a href="./../concepts/piece-cids">Piece-CIDs</a>.</p><h2 id="prover" tabindex="-1">Prover <a class="header-anchor" href="#prover" aria-label="Permalink to &quot;Prover&quot;">​</a></h2><p>A node operator who runs <code>provad</code>, stakes USDC, stores client bytes, and posts daily proofs. Earns USDC per successful proof.</p><h2 id="redundancy-replication-factor" tabindex="-1">Redundancy / replication factor <a class="header-anchor" href="#redundancy-replication-factor" aria-label="Permalink to &quot;Redundancy / replication factor&quot;">​</a></h2><p>How many independent provers hold a copy of the same piece. Default 4. Higher = more durable, more expensive.</p><h2 id="slashing" tabindex="-1">Slashing <a class="header-anchor" href="#slashing" aria-label="Permalink to &quot;Slashing&quot;">​</a></h2><p>The protocol&#39;s punishment for a prover that fails to post proofs. Their staked USDC is destroyed (or partially refunded to the client). See <a href="./../concepts/resilience">Resilience</a>.</p><h2 id="stake" tabindex="-1">Stake <a class="header-anchor" href="#stake" aria-label="Permalink to &quot;Stake&quot;">​</a></h2><p>USDC a prover locks into <code>ProverStaking.sol</code> to register capacity. The stake is the prover&#39;s skin in the game; missed proofs eat into it.</p><h2 id="term" tabindex="-1">Term <a class="header-anchor" href="#term" aria-label="Permalink to &quot;Term&quot;">​</a></h2><p>The duration of a deal, in seconds. Default 30 days, max 5 years.</p><h2 id="token-api" tabindex="-1">Token (API) <a class="header-anchor" href="#token-api" aria-label="Permalink to &quot;Token (API)&quot;">​</a></h2><p>A bearer credential issued by <code>/api/auth/signup</code>. HS256-signed JWT with a <code>pk_live_</code> prefix. See <a href="./../api/authentication">Authentication</a>.</p>',31)])])}const u=a(i,[["render",s]]);export{f as __pageData,u as default};
